const markets = $input.first().json.markets;

const vix   = markets.us.find(item => item.stock === "VIX:INDEXCBOE");
const sp500 = markets.futures.find(item => item.name === "S&P Futures");

if (!vix || !sp500) {
  throw new Error(`데이터 누락 - vix: ${!!vix}, sp500: ${!!sp500}`);
}

return [{
  json: {
    vix: vix.price,                                          // 예: 23.1
    vix_movement: vix.price_movement.movement,               // "Up" | "Down"
    sp500_futures: sp500.price,                              // 예: 6834.5
    sp500_futures_movement: sp500.price_movement.movement    // "Up" | "Down"
  }
}];

const summary = $input.first().json.summary;

if (!summary) throw new Error('데이터 누락 - summary 필드 없음');

return [{
  json: {
    usd_krw: summary.extracted_price,                  // 예: 1480.3
    usd_krw_movement: summary.price_movement.movement  // "Up" (원화 약세)
  }
}];

const summary = $input.first().json.summary;

if (!summary) throw new Error('데이터 누락 - summary 필드 없음');

return [{
  json: {
    kospi: summary.extracted_price,                  // 예: 5093.54
    kospi_movement: summary.price_movement.movement  // "Down" (하락)
  }
}];

const market_data = $input.first().json;
const { fear_greed_score, vix } = market_data;

let condition;
let trade_allowed;
let sentiment_label;

if (fear_greed_score < 25 || fear_greed_score > 74 || vix >= 30) {
  // Extreme Fear / Extreme Greed / VIX 급등 → 역발상 기회 구간
  condition       = "DANGER";
  trade_allowed   = true;
  sentiment_label = fear_greed_score < 25 ? "EXTREME_FEAR"
                  : fear_greed_score > 74 ? "EXTREME_GREED"
                  : "VIX_VOLATILITY_SPIKE";

} else if (fear_greed_score < 50 || vix >= 20) {
  // 불안 심리 / 변동성 경계 구간 → 관망
  condition       = "CAUTION";
  trade_allowed   = false;
  sentiment_label = "MARKET_CAUTION";

} else {
  // 안정적 상승 구간
  condition       = "NORMAL";
  trade_allowed   = false;
  sentiment_label = "MARKET_NORMAL";
}

return { ...market_data, condition, trade_allowed, sentiment_label };

