// 가재(Gajae)가 생성한 브리핑을 텔레그램으로 전송합니다.
var briefing = "";

// n8n Code 노드에서 $json 변수를 안전하게 확인합니다.
if (typeof $json !== "undefined" && $json.choices && $json.choices.length > 0 && $json.choices[0].message && $json.choices[0].message.content) {
    briefing = $json.choices[0].message.content;
} else if (typeof $json !== "undefined") {
    briefing = $json.aiContent || $json.content || "";
}

var result_final = { success: false, error: "Initialization failed" };

if (!briefing) {
    result_final = {
        success: false,
        error: "가재가 브리핑 내용을 생성하지 않았습니다.",
        input_data: (typeof $json !== "undefined" ? $json : "No $json found")
    };
    return result_final;
}

const token = "7970537683:AAH0QmWImg0LKzEjHY7fn5kWwcpgIzVmoWY";
const chatId = "1290448372";

// 텔레그램 메시지 전송 함수
async function sendToTelegram(text, parseMode) {
    var body = {
        chat_id: chatId,
        text: text
    };
    if (parseMode) {
        body.parse_mode = parseMode;
    }

    const response = await fetch("https://api.telegram.org/bot" + token + "/sendMessage", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body)
    });
    return response;
}

async function run() {
    try {
        // 1차 시도: Markdown
        let response = await sendToTelegram(briefing, "Markdown");
        let result = await response.json();

        // Markdown 오류 시 일반 텍스트로 전환하여 재시도
        if (!response.ok && result.description && result.description.indexOf("can't parse entities") !== -1) {
            response = await sendToTelegram(briefing, null);
            result = await response.json();
        }

        var msgId = (result.result && result.result.message_id) ? result.result.message_id : null;

        return {
            success: response.ok,
            message_id: msgId,
            status_code: response.status,
            response_body: result,
            briefing_preview: briefing.substring(0, 100) + "..."
        };
    } catch (error) {
        return {
            success: false,
            error: error.message
        };
    }
}

return run();
